import com.fasterxml.jackson.annotation.JsonAutoDetect;
import com.fasterxml.jackson.annotation.PropertyAccessor;
import tools.jackson.databind.ObjectMapper;

public class AnonymousUpdateRepro {
    public static void main(String[] args) throws Exception {
        Object resultObject = new Object() {
            int value;
        };
        ObjectMapper mapper = new ObjectMapper();
        mapper.setVisibility(PropertyAccessor.FIELD, JsonAutoDetect.Visibility.ANY);
        Object result = mapper.readerForUpdating(resultObject).readValue("{\"value\":2}");
        java.lang.reflect.Field f = resultObject.getClass().getDeclaredField("value");
        f.setAccessible(true);
        if (result != resultObject || ((Integer) f.get(resultObject)).intValue() != 2) {
            throw new IllegalStateException("Update failed: result=" + result + ", value=" + f.get(resultObject));
        }
        System.out.println("updated anonymous value=" + f.get(resultObject));
    }
}
EOF
