import com.fasterxml.jackson.annotation.JsonAutoDetect;
import com.fasterxml.jackson.annotation.PropertyAccessor;
import tools.jackson.databind.ObjectMapper;
import tools.jackson.databind.json.JsonMapper;

public class AnonymousUpdateEdges {
    public static void main(String[] args) throws Exception {
        ObjectMapper mapper = JsonMapper.builder()
                .changeDefaultVisibility(vc -> vc.withVisibility(PropertyAccessor.FIELD,
                        JsonAutoDetect.Visibility.ANY))
                .build();

        Object anonymous = new Object() { int value; };
        Object anonResult = mapper.readerForUpdating(anonymous).readValue("{\"value\":3}");
        assertValue("anonymous", anonymous, anonResult, 3);

        class LocalBean { int value; }
        LocalBean local = new LocalBean();
        Object localResult = mapper.readerForUpdating(local).readValue("{\"value\":4}");
        assertValue("local", local, localResult, 4);

        try {
            mapper.readerFor(anonymous.getClass()).readValue("{\"value\":5}");
            System.out.println("fresh anonymous read succeeded");
        } catch (Exception e) {
            System.out.println("fresh anonymous read failed: " + e.getClass().getSimpleName());
        }
    }

    private static void assertValue(String label, Object target, Object result, int expected) throws Exception {
        java.lang.reflect.Field f = target.getClass().getDeclaredField("value");
        f.setAccessible(true);
        int actual = f.getInt(target);
        if (result != target || actual != expected) {
            throw new IllegalStateException(label + " update failed: " + actual);
        }
        System.out.println(label + " update value=" + actual);
    }
}

